import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';

export interface CreateRequestDto {
  title: string;
  department: string;
  sponsorshipType: string;
  eventName: string;
  eventDate: Date;
  requestedAmount: number;
  justification: string;
  expectedBenefit?: string;
  remarks?: string;
}

export interface SponsorshipRequest {
  id: number;
  title: string;
  requestorId: number;
  requestorName?: string;
  department: string;
  sponsorshipType: string;
  eventName: string;
  eventDate: Date;
  requestedAmount: number;
  justification: string;
  expectedBenefit?: string;
  remarks?: string;
  status: string;
  createdAt: Date;
  submittedAt?: Date;
  managerRemarks?: string;
  financeRemarks?: string;
}

export interface ApprovalDto {
  requestId: number;
  userId: number;
  remarks: string;
}

export interface WorkflowHistory {
  id: number;
  requestId: number;
  action: string;
  actorUserId: number;
  actorName?: string;
  remarks: string;
  oldStatus: string;
  newStatus: string;
  timestamp: Date;
}

@Injectable({
  providedIn: 'root'
})

export class RequestService {
  private apiUrl = environment.apiUrl;

  constructor(private http: HttpClient) { }

  createRequest(requestData: CreateRequestDto): Observable<any> {
    return this.http.post(`${this.apiUrl}/requests`, requestData);
  }

  submitRequest(requestId: number): Observable<any> {
    return this.http.put(`${this.apiUrl}/requests/${requestId}/submit`, {});
  }

  getMyRequests(): Observable<SponsorshipRequest[]> {
    return this.http.get<SponsorshipRequest[]>(`${this.apiUrl}/requests/my`);
  }

  getRequestById(id: number): Observable<SponsorshipRequest> {
    return this.http.get<SponsorshipRequest>(`${this.apiUrl}/requests/${id}`);
  }

  updateRequest(id: number, requestData: Partial<CreateRequestDto>): Observable<any> {
    return this.http.put(`${this.apiUrl}/requests/${id}`, requestData);
  }

  cancelRequest(id: number): Observable<any> {
    return this.http.put(`${this.apiUrl}/requests/${id}/cancel`, {});
  }

  getPendingManagerRequests(): Observable<SponsorshipRequest[]> {
    return this.http.get<SponsorshipRequest[]>(`${this.apiUrl}/requests/pending-manager`);
  }

  approveByManager(requestId: number, userId: number, remarks: string): Observable<any> {
    const approvalData: ApprovalDto = { requestId, userId, remarks };
    return this.http.post(`${this.apiUrl}/requests/manager-approve`, approvalData);
  }

  rejectByManager(requestId: number, userId: number, remarks: string): Observable<any> {
    const approvalData: ApprovalDto = { requestId, userId, remarks };
    return this.http.post(`${this.apiUrl}/requests/manager-reject`, approvalData);
  }

  getPendingFinanceRequests(): Observable<SponsorshipRequest[]> {
    return this.http.get<SponsorshipRequest[]>(`${this.apiUrl}/requests/pending-finance`);
  }

  approveByFinance(requestId: number, userId: number, remarks: string): Observable<any> {
    const approvalData: ApprovalDto = { requestId, userId, remarks };
    return this.http.post(`${this.apiUrl}/requests/finance-approve`, approvalData);
  }

  rejectByFinance(requestId: number, userId: number, remarks: string): Observable<any> {
    const approvalData: ApprovalDto = { requestId, userId, remarks };
    return this.http.post(`${this.apiUrl}/requests/finance-reject`, approvalData);
  }

  getAllRequests(): Observable<SponsorshipRequest[]> {
    return this.http.get<SponsorshipRequest[]>(`${this.apiUrl}/requests/all`);
  }

  getRequestHistory(requestId: number): Observable<WorkflowHistory[]> {
    return this.http.get<WorkflowHistory[]>(`${this.apiUrl}/requests/${requestId}/history`);
  }
}
